import React from "react";


const reviews = [
    {
        review: "C3Ops reduced our cloud costs significantly while giving us deep, actionable insights. It’s an essential tool for any cloud-driven team.",
        name: "Jhon",
        owner: "Manager at Capgemini",
    },
    {
        review: "A seamless fusion of FinOps and DevOps that has completely transformed our team’s efficiency. Truly a game changer.",
        name: "Raghu Sharma",
        owner: "Manager at American Bank"
    },
    {
        review: "Enhanced visibility into our multi-cloud infrastructure has revolutionized the way we manage and optimize cloud costs.",
        name: "Mthu Shetty",
        owner: "Team Lead at Hitachi"
    },
    {
        review: "We now have full transparency across our cloud usage, enabling us to optimize costs and improve performance effortlessly.",
        name: "Sharma",
        owner: "Founder Of RR"
    }
]

const Review = () => {
  return (
    <>
      <div className="container">
        <div className="header-container">
            <h1>Powered by Leading Cloud-Native Companies</h1>
          <p>Backed by Top Cloud-Native Enterprises</p>

          {review.map((li))}
        </div>
      </div>
    </>
  );
};

export default Review;
